import React from "react";
import { useCart } from "./CartContext";

const medicines = [
  "Paracetamol",
  "Ibuprofen",
  "Amoxicillin",
  "Cetirizine",
  "Vitamin C",
  "Dolo 650",
  "Azithromycin"
];

function Help() {
  const { cartItems, addToCart, increaseQty, decreaseQty } = useCart();

  return (
    <div>
      <h2>Medicines</h2>

      <div className="medicine-grid">
        {medicines.map((med, index) => {
          const cartItem = cartItems.find((i) => i.name === med);
          const qty = cartItem ? cartItem.quantity : 0;

          return (
            <div key={index} className="medicine-card">
              <h4>{med}</h4>

              {qty === 0 ? (
                <button
                  onClick={() =>
                    addToCart({
                      id: index + 1, // IMPORTANT FIX
                      name: med
                    })
                  }
                >
                  Add to Cart
                </button>
              ) : (
                <div className="qty-controls">
                  <button onClick={() => decreaseQty(index + 1)}>-</button>

                  <span>{qty}</span>

                  <button
                    onClick={() => increaseQty(index + 1)}
                    disabled={qty >= 5}
                  >
                    +
                  </button>
                </div>
              )}

              {qty >= 5 && (
                <small className="limit-text">Max limit reached</small>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}

export default Help;
